import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define the custom CUDA kernel for parallel prefix sum
scan_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>

// Algorithm constants - named for clarity and robustness
constexpr int BINARY_TREE_BRANCHING = 2;
constexpr int INITIAL_OFFSET = 1;

// Helper for power-of-two validation
__device__ __host__ bool is_power_of_two(int n) {
    return (n > 0) && ((n & (n - 1)) == 0);
}

template<typename T>
__global__ void row_scan_kernel(const T* input, T* output, int rows, int cols) {
    int row = blockIdx.x;
    int tid = threadIdx.x;

    if (row >= rows) return;

    // Validate algorithm preconditions
    if (row == 0 && tid == 0) {
        if (!is_power_of_two(cols)) {
            // Fallback to sequential scan for non-power-of-two
            // This ensures correctness at performance cost
            for (int r = 0; r < rows; r++) {
                T accum = 0;
                for (int c = 0; c < cols; c++) {
                    accum += input[r * cols + c];
                    output[r * cols + c] = accum;
                }
            }
            return;
        }
    }
    __syncthreads();

    extern __shared__ T shared[];

    // Load row into shared memory with bounds checking
    for (int i = tid; i < cols; i += blockDim.x) {
        shared[i] = input[row * cols + i];
    }
    __syncthreads();

    // Perform parallel scan (Blelloch algorithm) with proper constants
    int offset = INITIAL_OFFSET;

    // Up-sweep phase
    for (int d = cols / BINARY_TREE_BRANCHING; d > 0; d /= BINARY_TREE_BRANCHING) {
        if (tid < d) {
            int ai = offset * (BINARY_TREE_BRANCHING * tid + 1) - 1;
            int bi = offset * (BINARY_TREE_BRANCHING * tid + 2) - 1;

            // Bounds check
            if (bi < cols) {
                shared[bi] += shared[ai];
            }
        }
        offset *= BINARY_TREE_BRANCHING;
        __syncthreads();
    }

    // Down-sweep phase
    if (tid == 0) {
        shared[cols - 1] = 0;
    }

    for (int d = 1; d < cols; d *= BINARY_TREE_BRANCHING) {
        offset /= BINARY_TREE_BRANCHING;
        __syncthreads();

        if (tid < d) {
            int ai = offset * (BINARY_TREE_BRANCHING * tid + 1) - 1;
            int bi = offset * (BINARY_TREE_BRANCHING * tid + 2) - 1;

            // Bounds check
            if (bi < cols) {
                T t = shared[ai];
                shared[ai] = shared[bi];
                shared[bi] += t;
            }
        }
    }
    __syncthreads();

    // Store results with bounds checking
    for (int i = tid; i < cols; i += blockDim.x) {
        output[row * cols + i] = shared[i];
    }
}

torch::Tensor parallel_scan_cuda(torch::Tensor x, int dim) {
    // Get tensor dimensions
    auto sizes = x.sizes();
    int n = sizes[dim];
    int total_elements = x.numel();
    int outer_elements = total_elements / n;

    // Validate input
    TORCH_CHECK(n > 0, "Scan dimension must be positive");
    TORCH_CHECK(outer_elements > 0, "Outer elements must be positive");

    // Reshape to 2D: (outer_elements, n) for easier processing
    auto x_reshaped = x.reshape({outer_elements, n}).contiguous();
    auto out = torch::zeros_like(x_reshaped);

    // Get data pointers
    auto x_ptr = x_reshaped.data_ptr<float>();
    auto out_ptr = out.data_ptr<float>();

    // Configure kernel launch
    int threads = min(256, n);
    int shared_mem_size = n * sizeof(float);

    // Validate shared memory requirements
    cudaDeviceProp prop;
    cudaGetDeviceProperties(&prop, 0);
    TORCH_CHECK(shared_mem_size <= prop.sharedMemPerBlock, 
                "Required shared memory exceeds device limit");

    // Launch one block per row
    row_scan_kernel<float><<<outer_elements, threads, shared_mem_size>>>(
        x_ptr, out_ptr, outer_elements, n
    );

    // Check for kernel errors
    cudaError_t err = cudaGetLastError();
    TORCH_CHECK(err == cudaSuccess, 
                "CUDA kernel failed: ", cudaGetErrorString(err));

    // Reshape back to original shape
    return out.reshape(sizes);
}
"""

scan_cpp_source = """
torch::Tensor parallel_scan_cuda(torch::Tensor x, int dim);
"""

# Compile the inline CUDA code
scan_module = load_inline(
    name="parallel_scan",
    cpp_sources=scan_cpp_source,
    cuda_sources=scan_source,
    functions=["parallel_scan_cuda"],
    verbose=False,
    with_cuda=True,
    extra_cuda_cflags=["-O3"],
)


class ModelNew(nn.Module):
    """
    Optimized model that performs cumulative sum using custom CUDA kernels.

    Parameters:
        dim (int): The dimension along which to perform the scan operation.
    """

    def __init__(self, dim):
        """
        Initialize the optimized Scan model.

        Args:
            dim (int): The dimension along which to perform the cumulative sum.
        """
        super(ModelNew, self).__init__()
        self.dim = dim
        self.scan_module = scan_module

    def forward(self, x):
        """
        Forward pass using optimized parallel scan.

        Args:
            x (torch.Tensor): Input tensor.

        Returns:
            torch::Tensor: Tensor after applying cumulative sum along specified dimension.
        """
        return self.scan_module.parallel_scan_cuda(x, self.dim)
